import java.io.IOException;
import java.io.PrintWriter;
import org.apache.commons.text.StringEscapeUtils; // Import Apache Commons Text library for HTML escaping

public class XSSSecureCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Escape user input using Apache Commons Text library
        String escapedUserInput = StringEscapeUtils.escapeHtml4(userInput);

        // Properly handle user input by outputting the escaped version to the webpage
        PrintWriter out = new PrintWriter(System.out);
        out.println("<p>User Input: " + escapedUserInput + "</p>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
